INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '73a1be5b-e532-4169-876d-c90bfff7fbae',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kubernetes Architecture — Control Plane vs Worker Nodes, etcd, and the API Server$escape$,
  $escape$Every Kubernetes cluster splits into two planes: the control plane (brain) and worker nodes (muscle). The control plane runs four critical components: kube-apiserver, etcd, kube-scheduler, and kube-controller-manager. All cluster state — Deployments, Services, ConfigMaps — lives exclusively in etcd, a distributed key-value store using the Raft consensus algorithm. Nothing talks to etcd directly except kube-apiserver.

kube-apiserver is the single entry point for all operations. kubectl, controllers, and kubelets all communicate through it via the Kubernetes REST API. It validates and persists objects to etcd, then emits watch events to downstream components.

kube-scheduler watches for unscheduled Pods (spec.nodeName is empty) and assigns them to nodes based on resource requests, taints/tolerations, and affinity rules. kube-controller-manager runs reconciliation loops — the ReplicaSet controller ensures desired vs actual pod count matches continuously.

On worker nodes, kubelet watches the API server for Pods assigned to its node and drives the container runtime (containerd via CRI) to converge actual state. kube-proxy maintains iptables/IPVS rules for Service networking. No control-plane components run on workers by default.$escape$,
  $escape$# Inspect control plane component health
kubectl get componentstatuses

# View raw etcd keys (requires etcdctl + cluster certs)
ETCDCTL_API=3 etcdctl \
  --endpoints=https://127.0.0.1:2379 \
  --cacert=/etc/kubernetes/pki/etcd/ca.crt \
  --cert=/etc/kubernetes/pki/etcd/server.crt \
  --key=/etc/kubernetes/pki/etcd/server.key \
  get /registry/pods/default --prefix --keys-only

# Check which node a pod is scheduled to and why
kubectl get pod <pod-name> -o jsonpath='{.spec.nodeName}'
kubectl describe pod <pod-name> | grep -A5 Events$escape$,
