INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd91a189d-cc9a-4643-ad8d-9efd73ef97eb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kubernetes Helm — Chart Structure, Values, and Release Lifecycle in Practice$escape$,
  $escape$Helm packages Kubernetes manifests into charts — a directory with a Chart.yaml, a templates/ folder, and a values.yaml. Templates use Go's text/template engine with Helm-specific functions from the Sprig library. Values flow in via values.yaml, --set flags, or -f overrides, with later sources winning. Inside templates, .Values, .Release, .Chart, and .Capabilities are the four built-in objects. .Release.Name scopes resource names to prevent collisions across installs in the same namespace.

Helm tracks releases as Secrets (v3) in the target namespace, storing each revision's rendered manifests. helm upgrade --install is idempotent — install on first run, upgrade on subsequent. helm rollback <release> <revision> restores a previous Secret's state and re-applies it. Use helm diff (the plugin) before any upgrade to catch unintended drift. Subcharts live in charts/ and inherit globals from the parent's values under a matching key. Always pin appVersion in Chart.yaml and lock dependencies with helm dependency update, which writes Chart.lock — commit both.$escape$,
  $escape$# Install with custom values, then inspect and rollback
helm dependency update ./my-chart

helm upgrade --install my-app ./my-chart \
  --namespace production \
  --create-namespace \
  -f ./my-chart/values.prod.yaml \
  --set image.tag=v1.4.2 \
  --atomic \
  --timeout 3m

# Inspect rendered manifests before applying
helm diff upgrade my-app ./my-chart -f ./my-chart/values.prod.yaml

# View release history and rollback
helm history my-app -n production
helm rollback my-app 3 -n production$escape$,
  $escape$bash$escape$,
