INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '351bb453-c766-4012-9ba3-cc700824f24b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kubernetes Autoscaling — HPA, VPA, and KEDA for Every Workload$escape$,
  $escape$Kubernetes ships three complementary autoscalers — each solves a different problem. HPA (HorizontalPodAutoscaler) scales replica count based on CPU/memory or custom metrics exposed via the Metrics API. It reacts in seconds but can't help when your pods are under-resourced to begin with. VPA (VerticalPodAutoscaler) addresses that: it watches historical usage and adjusts `requests`/`limits` on pods, though it requires a pod restart on resize in most modes (`Auto`, `Recreate`). Neither handles event-driven workloads well. KEDA (Kubernetes Event-Driven Autoscaler) fills that gap — it installs as a CRD + controller and scales Deployments or Jobs from zero based on external queue depth, Kafka lag, Prometheus queries, or 60+ other scalers. KEDA emits a `ScaledObject` that drives an HPA internally, so they compose rather than conflict. A common pattern: VPA in `Off` mode for recommendations → tune requests → enable HPA on CPU → layer KEDA for queue-driven burst. Avoid running VPA `Auto` and HPA on the same metric simultaneously — they'll fight.$escape$,
  $escape$# keda-scaledobject.yaml — scale a Deployment from Kafka consumer lag
apiVersion: keda.sh/v1alpha1
kind: ScaledObject
metadata:
  name: orders-processor-scaler
spec:
  scaleTargetRef:
    name: orders-processor
  minReplicaCount: 0          # scale to zero when idle
  maxReplicaCount: 50
  triggers:
  - type: kafka
    metadata:
      bootstrapServers: kafka.default.svc:9092
      consumerGroup: orders-group
      topic: orders
      lagThreshold: "100"      # one replica per 100 unprocessed messages$escape$,
  $escape$bash$escape$,
