INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd3a758a6-0723-4bc2-8fd4-9635ce5466a2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kubernetes RBAC & Namespaces — Enforcing Multi-Tenancy with Least Privilege$escape$,
  $escape$Namespaces partition cluster resources but provide zero security isolation on their own — RBAC is what enforces it. The pattern: one Namespace per team, a ServiceAccount per workload, and RoleBindings that scope permissions to that Namespace only. Never use ClusterRoleBindings unless the subject genuinely needs cluster-wide access.

The least-privilege checklist: bind to Role (namespaced) over ClusterRole, grant specific verbs (get, list, watch) rather than wildcards, and avoid binding to the default ServiceAccount — it's shared by every Pod in the Namespace. Audit existing bindings with kubectl auth can-i --list --as=system:serviceaccount:<ns>:<sa> -n <ns> before shipping.

For multi-tenant clusters, pair RBAC with ResourceQuota and LimitRange per Namespace to prevent noisy-neighbor CPU/memory exhaustion. Use NetworkPolicy to block cross-namespace traffic by default — RBAC controls the API server, not the data plane. Combine both layers or a compromised Pod can still reach adjacent Namespaces over the network even if it can't call kubectl.$escape$,
  $escape$# Role granting read-only Pod access within a single namespace
apiVersion: rbac.authorization.k8s.io/v1
kind: Role
metadata:
  name: pod-reader
  namespace: team-alpha
rules:
- apiGroups: [""]
  resources: ["pods", "pods/log"]
  verbs: ["get", "list", "watch"]
---
apiVersion: rbac.authorization.k8s.io/v1
kind: RoleBinding
metadata:
  name: pod-reader-binding
  namespace: team-alpha
subjects:
- kind: ServiceAccount
  name: api-worker
  namespace: team-alpha
roleRef:
  kind: Role
  name: pod-reader
  apiGroup: rbac.authorization.k8s.io$escape$,
  $escape$bash$escape$,
